<template>
  <Teleport to="body">
    <div ref="backdropRef" class="pa-modal-backdrop" role="presentation" @click.self="close">
      <section ref="modalRef" class="pa-modal" role="dialog" aria-modal="true" :aria-labelledby="titleId" :aria-busy="props.closeDisabled ? 'true' : 'false'" :style="themeVars" tabindex="-1">
        <header class="pa-modal-head">
          <img class="pa-modal-logo" :src="institutionLogo" :alt="institutionName" />
          <div>
            <p v-if="eyebrow" class="eyebrow">{{ eyebrow }}</p>
            <h2 :id="titleId">{{ title }}</h2>
            <p v-if="description">{{ description }}</p>
          </div>
          <button class="pa-modal-close" type="button" aria-label="Cerrar" :disabled="props.closeDisabled" @click="close">×</button>
        </header>
        <div class="pa-modal-body">
          <slot />
        </div>
      </section>
    </div>
  </Teleport>
</template>

<script setup lang="ts">
import { computed, nextTick, onBeforeUnmount, onMounted, ref, useId } from 'vue'
import type { PersonasTheme } from '~/types/daycare'
import { personasInstitutionLogo, personasInstitutionName, personasThemeStyle, resolvePersonasTheme } from '~/utils/personasTheme'

const props = withDefaults(defineProps<{
  title: string
  eyebrow?: string
  description?: string
  closeDisabled?: boolean
  theme?: PersonasTheme | null
}>(), {
  closeDisabled: false
})

const emit = defineEmits<{ close: [] }>()
const modalRef = ref<HTMLElement | null>(null)
const backdropRef = ref<HTMLElement | null>(null)
const previousActive = ref<HTMLElement | null>(null)
const titleId = `pa-modal-title-${useId()}`
const resolvedTheme = computed(() => props.theme || resolvePersonasTheme({}))
const themeVars = computed(() => personasThemeStyle(resolvedTheme.value))
const institutionLogo = computed(() => personasInstitutionLogo(resolvedTheme.value, 'logo'))
const institutionName = computed(() => personasInstitutionName(resolvedTheme.value))

function close() {
  if (props.closeDisabled) return
  emit('close')
}

function focusableElements() {
  return Array.from(modalRef.value?.querySelectorAll<HTMLElement>([
    'a[href]',
    'button:not([disabled])',
    'input:not([disabled])',
    'select:not([disabled])',
    'textarea:not([disabled])',
    '[tabindex]:not([tabindex="-1"])'
  ].join(',')) || []).filter((element) => !element.hasAttribute('aria-hidden'))
}

function onKeydown(event: KeyboardEvent) {
  if (event.key === 'Escape') {
    if (!props.closeDisabled) close()
    return
  }
  if (event.key !== 'Tab') return
  const items = focusableElements()
  if (!items.length) {
    event.preventDefault()
    modalRef.value?.focus()
    return
  }
  const first = items[0]
  const last = items[items.length - 1]
  if (event.shiftKey && document.activeElement === first) {
    event.preventDefault()
    last.focus()
  } else if (!event.shiftKey && document.activeElement === last) {
    event.preventDefault()
    first.focus()
  }
}

onMounted(async () => {
  previousActive.value = document.activeElement instanceof HTMLElement ? document.activeElement : null
  document.addEventListener('keydown', onKeydown)
  document.body.classList.add('pa-modal-open')
  await nextTick()
  const firstFocusable = focusableElements()[0]
  if (firstFocusable) {
    firstFocusable.focus()
  } else {
    modalRef.value?.focus()
  }
})

onBeforeUnmount(() => {
  document.removeEventListener('keydown', onKeydown)
  document.body.classList.remove('pa-modal-open')
  previousActive.value?.focus?.()
})

</script>

